// Heuristic difficulty so generated items span easy/medium/advanced — this lets the self-test
// blueprint (which draws by band) and the practice/consolidation ramp use them properly.
// Recognition/meaning (vocabulary, functions, notions) → easy; grammar MCQ → medium; fill-in
// (production) → advanced. An explicit q.difficulty always wins.
const RECOGNITION = new Set([
  "vocabulary", "functions", "reading", "volition", "register",
  "knowledge_ignorance", "certainty_doubt", "stability_change", "sentiments",
]);
function diffOf(q: MCQ | FILL): "easy" | "medium" | "advanced" {
  if (q.difficulty) return q.difficulty;
  if (!("options" in q)) return "advanced"; // fill_blank = production
  return RECOGNITION.has(q.concept) ? "easy" : "medium";
}

let total = 0;
const summary: Record<string, number> = {};
for (const ofStr of Object.keys(SETS)) {
  const of = Number(ofStr);
  const obj = objOf(of);
  const path = join(ROOT, "content", "question-bank", "items", `OF${of}.json`);
  const bank = JSON.parse(readFileSync(path, "utf8"));
  // drop previously generated items (idempotent)
  bank.items = bank.items.filter((it: any) => !it.generated);

  let n = 0;
  for (const q of SETS[of]) {
    n++;
    const base = {
      id: `itm_of${of}_gen_${n}`, objectiveId: `OF${of}`, generated: true,
      grammarConcepts: [q.concept], vocabDomains: obj?.vocabDomains ?? [], theme: obj?.themes?.[0] ?? "workplace",
      difficulty: diffOf(q), status: "live",
      tip: { memory_aid: q.tip, pattern: q.pattern, similar: ("options" in q ? q.options.slice(0, 2) : q.answer) },
    };
    if ("options" in q) {
      const correct = q.options[0];
      const distractors = [{ value: correct, tag: "correct" }, ...q.options.slice(1).map((o, i) => ({ value: o, tag: `d${i}` }))];
      const distractor_why: Record<string, string> = {};
      q.options.slice(1).forEach((_, i) => { distractor_why[`d${i}`] = q.dwhy[i]; });
      bank.items.push({
        ...base, skill: "grammar", type: "mcq_single", estTimeSec: 30, irtB: 0,
        prompt: { fr: q.fr, instructions_en: q.instr },
        answer: { type: "choice", accepted: [correct], normalizer: "fr_accent_insensitive_trim_lower" },
        distractors,
        explanation: { correct_why: q.why, distractor_why, grammar_rule: q.rule, vocab_notes: q.vocab ?? "Concept enseigné dans cet objectif (PFL2).", common_mistakes: ["choisir une forme proche mais incorrecte"] },
      });
    } else {
      bank.items.push({
        ...base, skill: "writing", type: "fill_blank", estTimeSec: 35, irtB: 0.2,
        prompt: { fr: q.fr, instructions_en: q.instr },
        answer: { type: "text", accepted: q.answer, normalizer: "fr_accent_insensitive_trim_lower" },
        distractors: [],
        explanation: { correct_why: q.why, distractor_why: {}, grammar_rule: q.rule, vocab_notes: q.vocab ?? "Concept enseigné dans cet objectif (PFL2).", common_mistakes: ["se tromper de forme ou d'accord"] },
      });
    }
  }
  if (bank.source?.counts) bank.source.counts.generated = n;
  writeFileSync(path, JSON.stringify(bank));
  summary[`OF${of}`] = n; total += n;
}
console.log(`Generated ${total} new concept-teaching questions:`, JSON.stringify(summary));
